class Solution:
    def numberOfPairs(self, points: list) -> int:
        n = len(points)
        count = 0
        for i in range(n):
            ax, ay = points[i]
            for j in range(n):
                if i == j:
                    continue
                bx, by = points[j]
                # A must be upper-left: ax<=bx and ay>=by
                if ax > bx or ay < by:
                    continue
                # Check no other point inside rectangle
                valid = True
                for t in range(n):
                    if t == i or t == j:
                        continue
                    cx, cy = points[t]
                    if ax <= cx <= bx and by <= cy <= ay:
                        valid = False
                        break
                if valid:
                    count += 1
        return count

