solutions.javascript:
var numberOfPairs = function(points) {
    const n = points.length;
    let count = 0;
    for (let i = 0; i < n; i++) {
        const [ax, ay] = points[i];
        for (let j = 0; j < n; j++) {
            if (i === j) continue;
            const [bx, by] = points[j];
            if (ax > bx || ay < by) continue;
            let valid = true;
            for (let t = 0; t < n; t++) {
                if (t === i || t === j) continue;
                const [cx, cy] = points[t];
                if (ax <= cx && cx <= bx && by <= cy && cy <= ay) { valid = false; break; }
            }
            if (valid) count++;
        }
    }
    return count;
};
